func (a *Analyzer) Clean() (int, int) {
	now := time.Now()
	total := 0
	count := 0

	a.mu.Lock()
	defer a.mu.Unlock()
	total = len(a.records)

	for key, records := range a.records {
		if now.Sub(records.LastUpdateTime) > a.dataReserveDuration {
			delete(a.records, key)
			count++
		}
	}
	return count, total
}
